import{_ as a,c as r,o as e,ag as o}from"./chunks/framework.XjE0kKti.js";const s="/gatewayweb/docs/assets/hub0022-services-overview.CZIbK5RJ.png",n="/gatewayweb/docs/assets/hub0022-instance-context-menu.BonTRMTJ.png",d="/gatewayweb/docs/assets/hub0022-proxy-config.BTq0uSXr.png",l="/gatewayweb/docs/assets/hub0022-add-service.-px7itse.png",i="/gatewayweb/docs/assets/hub0022-service-row-menu.DDz16nA0.png",h="/gatewayweb/docs/assets/hub0022-node-management.BEnmK-pP.png",P=JSON.parse('{"title":"代理管理","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0022.md","filePath":"modules/hub0022.md","lastUpdated":1776841524000}'),g={name:"modules/hub0022.md"};function b(c,t,p,u,m,_){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="代理管理" tabindex="-1">代理管理 <a class="header-anchor" href="#代理管理" aria-label="Permalink to &quot;代理管理&quot;">​</a></h1><p>用于在指定<strong>网关实例</strong>下维护“转发代理能力”的核心对象：<strong>服务定义</strong>与<strong>服务节点</strong>，并对实例配置代理相关的连接与超时参数（代理配置）。本模块通常与「路由管理（hub0021）」配合使用：路由负责“如何匹配请求”，代理负责“命中后转发到哪里、怎么转发”。</p><p><img src="'+s+'" alt="代理管理：实例与服务列表"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>代理管理聚焦三类工作：</p><ul><li><strong>选择网关实例</strong>：左侧实例列表决定你正在维护哪个实例的代理配置与服务目录。</li><li><strong>维护服务定义</strong>：右侧服务列表维护服务名称、服务类型（静态/服务发现）、负载均衡、会话亲和性、熔断与健康检查等。</li><li><strong>维护服务节点</strong>：对静态服务配置具体的节点地址、协议、权重与启用状态（服务发现型服务通常由注册中心发现，节点管理的使用方式以你们环境为准）。</li></ul><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>网关管理</strong> → <strong>代理管理</strong>。</p><hr><h2 id="页面布局" tabindex="-1">页面布局 <a class="header-anchor" href="#页面布局" aria-label="Permalink to &quot;页面布局&quot;">​</a></h2><p>页面为左右分栏：</p><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td>左侧</td><td><strong>网关实例列表</strong>：刷新、搜索过滤、选择实例；并提供实例级的 <strong>代理配置</strong> 入口。</td></tr><tr><td>右侧</td><td><strong>服务定义列表</strong>：对所选实例的服务定义进行查询、新增、编辑、删除与节点管理。</td></tr></tbody></table><hr><h2 id="操作说明" tabindex="-1">操作说明 <a class="header-anchor" href="#操作说明" aria-label="Permalink to &quot;操作说明&quot;">​</a></h2><h3 id="_1-选择目标网关实例" tabindex="-1">1. 选择目标网关实例 <a class="header-anchor" href="#_1-选择目标网关实例" aria-label="Permalink to &quot;1. 选择目标网关实例&quot;">​</a></h3><p>在左侧 <strong>网关实例列表</strong> 中：</p><ul><li>可通过搜索框按“实例名称、地址或端口”过滤。</li><li>单击某一实例后，右侧服务列表将切换到该实例（查询参数使用该实例 ID 作为 <code>proxyConfigId</code>）。</li></ul><h3 id="_2-配置实例级代理参数-可选" tabindex="-1">2. 配置实例级代理参数（可选） <a class="header-anchor" href="#_2-配置实例级代理参数-可选" aria-label="Permalink to &quot;2. 配置实例级代理参数（可选）&quot;">​</a></h3><p>对实例节点右键打开菜单，进入 <strong>代理配置</strong>。</p><p><img src="'+n+'" alt="实例节点菜单：代理配置"></p><p>代理配置对话框按代理类型展示不同页签（如 HTTP/WebSocket/TCP/UDP）；常用的 HTTP 配置包含连接超时、读写超时、重试次数、缓冲区大小、是否保持连接、是否保留原始 Host 等。</p><p><img src="'+d+'" alt="代理配置：HTTP参数示例"></p><p>建议：若出现上游请求慢、长连接、或大响应体等场景导致超时，可先从此处对齐连接与读写超时，并与上游 LB/WAF/客户端 SDK 的超时保持一致。</p><h3 id="_3-新增服务定义" tabindex="-1">3. 新增服务定义 <a class="header-anchor" href="#_3-新增服务定义" aria-label="Permalink to &quot;3. 新增服务定义&quot;">​</a></h3><p>在右侧点击 <strong>新增服务</strong>，填写服务标识与策略。</p><p><img src="'+l+'" alt="新增服务定义"></p><p>常见字段说明：</p><ul><li><strong>服务名称</strong>：服务的唯一标识，建议与业务域一致，便于路由引用与排障。</li><li><strong>服务类型</strong>： <ul><li><strong>静态配置</strong>：手工维护节点列表（常用于固定后端地址）。</li><li><strong>服务发现</strong>：由服务注册中心发现实例（是否需要手工节点管理以环境实现为准）。</li></ul></li><li><strong>负载均衡策略</strong>：轮询、随机、IP 哈希、最少连接、加权轮询、一致性哈希等。</li><li><strong>会话亲和性</strong>：用于让同一会话尽量落到同一后端节点。</li><li><strong>熔断/健康检查</strong>：用于提升不稳定后端场景下的可用性（具体参数项以界面为准）。</li></ul><hr><h2 id="服务定义列表" tabindex="-1">服务定义列表 <a class="header-anchor" href="#服务定义列表" aria-label="Permalink to &quot;服务定义列表&quot;">​</a></h2><h3 id="查询条件" tabindex="-1">查询条件 <a class="header-anchor" href="#查询条件" aria-label="Permalink to &quot;查询条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>服务名称</td><td>按服务名称筛选。</td></tr><tr><td>服务类型</td><td>静态配置 / 服务发现。</td></tr><tr><td>负载均衡策略</td><td>按策略筛选。</td></tr><tr><td>状态</td><td>启用 / 禁用。</td></tr></tbody></table><h3 id="工具栏操作" tabindex="-1">工具栏操作 <a class="header-anchor" href="#工具栏操作" aria-label="Permalink to &quot;工具栏操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td>新增服务</td><td>创建服务定义。</td></tr><tr><td>查看详情</td><td>查看所选服务的详细信息。</td></tr><tr><td>删除</td><td>支持批量删除（需先勾选）。</td></tr><tr><td>节点管理</td><td>打开服务节点管理对话框（针对所选服务）。</td></tr></tbody></table><h3 id="行右键菜单" tabindex="-1">行右键菜单 <a class="header-anchor" href="#行右键菜单" aria-label="Permalink to &quot;行右键菜单&quot;">​</a></h3><p>在服务行上右键可快速执行：查看详情、编辑、节点管理、删除。</p><p><img src="'+i+'" alt="服务行菜单：节点管理入口"></p><hr><h2 id="服务节点管理" tabindex="-1">服务节点管理 <a class="header-anchor" href="#服务节点管理" aria-label="Permalink to &quot;服务节点管理&quot;">​</a></h2><p>在服务行菜单或工具栏中进入 <strong>节点管理</strong>，可维护该服务的后端节点。</p><p><img src="'+h+'" alt="服务节点管理"></p><p>常见字段含义：</p><ul><li><strong>节点协议</strong>：HTTP/HTTPS。</li><li><strong>节点主机/端口</strong>：后端服务地址；表单会根据协议、主机、端口自动生成节点 URL。</li><li><strong>节点权重</strong>：用于加权类负载均衡策略。</li><li><strong>健康状态/在线状态/启用状态</strong>：用于判断节点是否参与转发（具体生效策略以网关实现为准）。</li></ul><hr><h2 id="与路由管理的关系" tabindex="-1">与路由管理的关系 <a class="header-anchor" href="#与路由管理的关系" aria-label="Permalink to &quot;与路由管理的关系&quot;">​</a></h2><ul><li><strong>代理管理（hub0022）</strong>：定义“可被转发的服务与节点”，并为实例配置代理/连接策略。</li><li><strong>路由管理（hub0021）</strong>：定义“请求如何命中路由，以及命中后关联哪个服务定义”。</li></ul><p>通常建议先在本页创建好服务定义与节点，再在路由中关联服务。</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因与处理</th></tr></thead><tbody><tr><td>右侧列表为空</td><td>先确认左侧已选择实例；未选择实例时不会发起服务列表查询。</td></tr><tr><td>节点健康但仍无法访问</td><td>检查节点协议/端口是否正确、网络是否可达、上游路由是否已关联该服务。</td></tr><tr><td>超时或连接被断开</td><td>优先对齐实例级 <strong>代理配置</strong> 中的连接/读写/总超时，并排查上游 LB/WAF 与客户端超时是否更短。</td></tr></tbody></table>',52)])])}const x=a(g,[["render",b]]);export{P as __pageData,x as default};
